// Neon Mahjong VR - 3D Tile Renderer (Extended)

import {
  World,
  BoxGeometry,
  Mesh,
  MeshStandardMaterial,
  Group,
  Object3D,
  Color,
  CanvasTexture,
  PointLight,
  AmbientLight,
  FogExp2,
  GridHelper,
  PlaneGeometry,
  MeshBasicMaterial,
  LineBasicMaterial,
  BufferGeometry,
  Line,
  Float32BufferAttribute,
  Vector3,
  Raycaster,
  Camera,
} from '@iwsdk/core';
import { TileInstance, GameState } from './state';
import { TILE_TYPES, THEMES, type ThemeDef } from './data';

// Tile dimensions (meters)
const TILE_W = 0.12;
const TILE_H = 0.16;
const TILE_D = 0.06;
const TILE_GAP = 0.005;
const LAYER_OFFSET = TILE_D + 0.002;

// ── Canvas texture generation ───────────────────────────────
const textureCache = new Map<string, CanvasTexture>();

function createTileTexture(label: string, color: string, suit: string): CanvasTexture {
  const key = `${label}|${color}|${suit}`;
  if (textureCache.has(key)) return textureCache.get(key)!;

  const canvas = document.createElement('canvas');
  canvas.width = 128;
  canvas.height = 128;
  const ctx = canvas.getContext('2d')!;

  // Background
  ctx.fillStyle = '#0a1628';
  ctx.fillRect(0, 0, 128, 128);

  // Border
  ctx.strokeStyle = color;
  ctx.lineWidth = 3;
  ctx.strokeRect(4, 4, 120, 120);

  // Suit indicator (small text at top)
  ctx.fillStyle = color + '66';
  ctx.font = 'bold 14px monospace';
  ctx.textAlign = 'center';
  const suitLabel = suit === 'dot' ? 'DOT' : suit === 'bam' ? 'BAM' : suit === 'char' ? 'CHR'
    : suit === 'wind' ? 'WND' : suit === 'dragon' ? 'DRG'
    : suit === 'flower' ? 'FLR' : 'SZN';
  ctx.fillText(suitLabel, 64, 24);

  // Main symbol
  ctx.fillStyle = color;
  ctx.font = 'bold 48px monospace';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText(label, 64, 72);

  // Glow effect
  ctx.shadowColor = color;
  ctx.shadowBlur = 15;
  ctx.fillText(label, 64, 72);
  ctx.shadowBlur = 0;

  const tex = new CanvasTexture(canvas);
  textureCache.set(key, tex);
  return tex;
}

// ── Renderer ────────────────────────────────────────────────
export class TileRenderer {
  private world: World;
  private state: GameState;
  private boardGroup: Group;
  private tileMeshes: Map<number, Mesh> = new Map();
  private tilePositions: Map<number, Vector3> = new Map(); // World positions for particles
  private currentTheme: ThemeDef;
  private raycaster: Raycaster;
  private floorGrid: GridHelper | null = null;
  private ambientLight: AmbientLight | null = null;
  private pointLights: PointLight[] = [];

  // Board centering offsets
  private centerX = 0;
  private centerY = 0;

  constructor(world: World, state: GameState) {
    this.world = world;
    this.state = state;
    this.boardGroup = new Group();
    this.currentTheme = THEMES[state.currentThemeIdx];
    this.raycaster = new Raycaster();
    this.setupScene();
  }

  private setupScene(): void {
    const scene = this.world.scene;

    // Background
    scene.background = new Color(this.currentTheme.bgColor);
    scene.fog = new FogExp2(this.currentTheme.fogColor, 0.04);

    // Ambient light
    this.ambientLight = new AmbientLight(this.currentTheme.ambientColor, 0.6);
    scene.add(this.ambientLight);

    // Point lights
    const createLight = (x: number, y: number, z: number, color: number, intensity: number) => {
      const light = new PointLight(color, intensity, 15);
      light.position.set(x, y, z);
      scene.add(light);
      this.pointLights.push(light);
      return light;
    };
    createLight(0, 3, 0, 0x00ccff, 2);
    createLight(-2, 2, -1, 0x0066ff, 1);
    createLight(2, 2, -1, 0x00ffcc, 1);

    // Floor grid
    this.floorGrid = new GridHelper(20, 40, this.currentTheme.gridColor, this.currentTheme.gridColor);
    this.floorGrid.position.y = -0.05;
    scene.add(this.floorGrid);

    // Board group
    this.boardGroup.position.set(0, 0.8, -1.5);
    scene.add(this.boardGroup);
  }

  // ── Board Rendering ───────────────────────────────────────
  buildBoard(): void {
    // Clear old tiles
    this.clearBoard();

    if (!this.state.board) return;

    const tiles = this.state.board.tiles;

    // Center the layout
    let minC = Infinity, maxC = -Infinity, minR = Infinity, maxR = -Infinity;
    for (const t of tiles) {
      if (t.col < minC) minC = t.col;
      if (t.col > maxC) maxC = t.col;
      if (t.row < minR) minR = t.row;
      if (t.row > maxR) maxR = t.row;
    }
    this.centerX = (minC + maxC) / 2;
    this.centerY = (minR + maxR) / 2;

    for (const tile of tiles) {
      const mesh = this.createTileMesh(tile);
      const x = (tile.col - this.centerX) * (TILE_W + TILE_GAP);
      const y = tile.layer * LAYER_OFFSET;
      const z = -(tile.row - this.centerY) * (TILE_H + TILE_GAP);
      mesh.position.set(x, y, z);
      mesh.userData['tileIdx'] = tile.idx;
      this.boardGroup.add(mesh);
      this.tileMeshes.set(tile.idx, mesh);

      // Cache world position for particles
      const worldPos = new Vector3();
      mesh.getWorldPosition(worldPos);
      this.tilePositions.set(tile.idx, new Vector3(
        this.boardGroup.position.x + x,
        this.boardGroup.position.y + y,
        this.boardGroup.position.z + z,
      ));
    }
  }

  private createTileMesh(tile: TileInstance): Mesh {
    const tileType = TILE_TYPES[tile.typeId];
    const texture = createTileTexture(tileType.label, tileType.color, tileType.suit);

    const edgeColor = new Color(this.currentTheme.tileEdge);
    const baseColor = new Color(this.currentTheme.tileBase);

    const topMat = new MeshStandardMaterial({
      map: texture,
      emissive: edgeColor,
      emissiveIntensity: 0.1,
      roughness: 0.4,
      metalness: 0.3,
    });
    const sideMat = new MeshStandardMaterial({
      color: baseColor,
      emissive: edgeColor,
      emissiveIntensity: 0.05,
      roughness: 0.5,
      metalness: 0.2,
    });
    const bottomMat = new MeshStandardMaterial({
      color: baseColor,
      roughness: 0.7,
      metalness: 0.1,
    });

    const materials = [sideMat, sideMat, topMat, bottomMat, sideMat, sideMat];
    const geo = new BoxGeometry(TILE_W, TILE_D, TILE_H);
    const mesh = new Mesh(geo, materials);
    mesh.castShadow = true;
    mesh.receiveShadow = true;

    return mesh;
  }

  clearBoard(): void {
    while (this.boardGroup.children.length > 0) {
      const child = this.boardGroup.children[0];
      this.boardGroup.remove(child);
      if (child instanceof Mesh) {
        child.geometry.dispose();
        const mats = Array.isArray(child.material) ? child.material : [child.material];
        mats.forEach(m => m.dispose());
      }
    }
    this.tileMeshes.clear();
    this.tilePositions.clear();
  }

  // ── Public accessors for particles ────────────────────────
  getTileWorldPos(idx: number): Vector3 | null {
    return this.tilePositions.get(idx) || null;
  }

  getThemeEdgeColor(): number {
    return this.currentTheme.tileEdge;
  }

  // ── Tile Updates ──────────────────────────────────────────
  removeTile(idx: number): void {
    const mesh = this.tileMeshes.get(idx);
    if (!mesh) return;

    const startY = mesh.position.y;
    const duration = 400;
    const start = performance.now();

    const animate = () => {
      const t = Math.min((performance.now() - start) / duration, 1);
      const ease = 1 - (1 - t) * (1 - t);

      mesh.scale.setScalar(1 - ease);
      mesh.position.y = startY + ease * 0.2;
      mesh.rotation.y = ease * Math.PI;

      const mats = Array.isArray(mesh.material) ? mesh.material : [mesh.material];
      for (const m of mats) {
        if (m instanceof MeshStandardMaterial) {
          m.opacity = 1 - ease;
          m.transparent = true;
        }
      }

      if (t < 1) {
        requestAnimationFrame(animate);
      } else {
        this.boardGroup.remove(mesh);
        mesh.geometry.dispose();
        const ms = Array.isArray(mesh.material) ? mesh.material : [mesh.material];
        ms.forEach(m => m.dispose());
        this.tileMeshes.delete(idx);
      }
    };
    requestAnimationFrame(animate);
  }

  updateTileVisual(idx: number, tile: TileInstance): void {
    const mesh = this.tileMeshes.get(idx);
    if (!mesh) return;

    const tileType = TILE_TYPES[tile.typeId];
    const texture = createTileTexture(tileType.label, tileType.color, tileType.suit);
    const mats = mesh.material as MeshStandardMaterial[];
    if (mats[2]) {
      mats[2].map = texture;
      mats[2].needsUpdate = true;
    }
  }

  setTileSelected(idx: number, selected: boolean): void {
    const mesh = this.tileMeshes.get(idx);
    if (!mesh) return;

    const mats = mesh.material as MeshStandardMaterial[];
    const selectedColor = new Color(this.currentTheme.tileSelected);

    for (const m of mats) {
      if (selected) {
        m.emissive = selectedColor;
        m.emissiveIntensity = 0.6;
      } else {
        m.emissive = new Color(this.currentTheme.tileEdge);
        m.emissiveIntensity = m === mats[2] ? 0.1 : 0.05;
      }
    }

    mesh.scale.setScalar(selected ? 1.1 : 1.0);
  }

  setTileHint(idx: number, highlight: boolean): void {
    const mesh = this.tileMeshes.get(idx);
    if (!mesh) return;

    const mats = mesh.material as MeshStandardMaterial[];
    for (const m of mats) {
      if (highlight) {
        m.emissive = new Color(0x00ff88);
        m.emissiveIntensity = 0.5;
      } else {
        m.emissive = new Color(this.currentTheme.tileEdge);
        m.emissiveIntensity = m === mats[2] ? 0.1 : 0.05;
      }
    }
  }

  clearHints(): void {
    if (!this.state.board) return;
    for (const tile of this.state.board.tiles) {
      if (!tile.removed) {
        this.setTileHint(tile.idx, false);
      }
    }
  }

  // ── Raycasting ────────────────────────────────────────────
  raycast(ndcX: number, ndcY: number, camera: Camera): number | null {
    this.raycaster.setFromCamera({ x: ndcX, y: ndcY } as any, camera);
    const hits = this.raycaster.intersectObjects(this.boardGroup.children, false);
    for (const hit of hits) {
      const tileIdx = hit.object.userData['tileIdx'];
      if (tileIdx !== undefined) return tileIdx as number;
    }
    return null;
  }

  // ── Theme ─────────────────────────────────────────────────
  applyTheme(themeIdx: number): void {
    this.currentTheme = THEMES[themeIdx];
    const scene = this.world.scene;

    scene.background = new Color(this.currentTheme.bgColor);
    if (scene.fog instanceof FogExp2) {
      (scene.fog as FogExp2).color = new Color(this.currentTheme.fogColor);
    }
    if (this.ambientLight) {
      this.ambientLight.color = new Color(this.currentTheme.ambientColor);
    }
    if (this.floorGrid) {
      scene.remove(this.floorGrid);
      this.floorGrid = new GridHelper(20, 40, this.currentTheme.gridColor, this.currentTheme.gridColor);
      this.floorGrid.position.y = -0.05;
      scene.add(this.floorGrid);
    }

    textureCache.clear();
    if (this.state.board) {
      this.buildBoard();
    }
  }

  // ── Refresh on shuffle ────────────────────────────────────
  refreshAllTiles(): void {
    if (!this.state.board) return;
    for (const tile of this.state.board.tiles) {
      if (!tile.removed) {
        this.updateTileVisual(tile.idx, tile);
      }
    }
  }

  // ── Cleanup ───────────────────────────────────────────────
  dispose(): void {
    this.clearBoard();
    textureCache.clear();
  }
}

// Neon Mahjong VR - Procedural Audio Manager

export class AudioManager {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private sfxGain: GainNode | null = null;
  private musicGain: GainNode | null = null;
  private musicOsc: OscillatorNode | null = null;
  private musicPlaying = false;

  masterVol = 1.0;
  sfxVol = 1.0;
  musicVol = 0.5;

  init(): void {
    if (this.ctx) return;
    try {
      this.ctx = new AudioContext();
      this.masterGain = this.ctx.createGain();
      this.masterGain.gain.value = this.masterVol;
      this.masterGain.connect(this.ctx.destination);

      this.sfxGain = this.ctx.createGain();
      this.sfxGain.gain.value = this.sfxVol;
      this.sfxGain.connect(this.masterGain);

      this.musicGain = this.ctx.createGain();
      this.musicGain.gain.value = this.musicVol * 0.15;
      this.musicGain.connect(this.masterGain);
    } catch { /* no audio */ }
  }

  private ensureCtx(): boolean {
    if (!this.ctx || !this.sfxGain) return false;
    if (this.ctx.state === 'suspended') this.ctx.resume();
    return true;
  }

  updateVolumes(): void {
    if (this.masterGain) this.masterGain.gain.value = this.masterVol;
    if (this.sfxGain) this.sfxGain.gain.value = this.sfxVol;
    if (this.musicGain) this.musicGain.gain.value = this.musicVol * 0.15;
  }

  // ── SFX ───────────────────────────────────────────────────
  private playTone(freq: number, dur: number, type: OscillatorType = 'sine', vol = 0.3): void {
    if (!this.ensureCtx()) return;
    const osc = this.ctx!.createOscillator();
    const gain = this.ctx!.createGain();
    osc.type = type;
    osc.frequency.value = freq;
    gain.gain.setValueAtTime(vol, this.ctx!.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, this.ctx!.currentTime + dur);
    osc.connect(gain);
    gain.connect(this.sfxGain!);
    osc.start();
    osc.stop(this.ctx!.currentTime + dur);
  }

  playSelect(): void {
    this.playTone(800, 0.1, 'sine', 0.2);
  }

  playDeselect(): void {
    this.playTone(400, 0.08, 'sine', 0.15);
  }

  playMatch(): void {
    this.playTone(523, 0.15, 'sine', 0.25);
    setTimeout(() => this.playTone(659, 0.15, 'sine', 0.25), 80);
    setTimeout(() => this.playTone(784, 0.2, 'sine', 0.3), 160);
  }

  playCombo(level: number): void {
    const baseFreq = 523 + (level - 1) * 50;
    this.playTone(baseFreq, 0.12, 'square', 0.15);
    setTimeout(() => this.playTone(baseFreq * 1.25, 0.12, 'square', 0.15), 60);
    setTimeout(() => this.playTone(baseFreq * 1.5, 0.15, 'square', 0.2), 120);
  }

  playInvalid(): void {
    this.playTone(200, 0.15, 'sawtooth', 0.15);
    setTimeout(() => this.playTone(180, 0.15, 'sawtooth', 0.15), 100);
  }

  playHint(): void {
    this.playTone(600, 0.1, 'triangle', 0.2);
    setTimeout(() => this.playTone(800, 0.15, 'triangle', 0.2), 100);
  }

  playShuffle(): void {
    for (let i = 0; i < 5; i++) {
      setTimeout(() => this.playTone(300 + Math.random() * 400, 0.05, 'sine', 0.1), i * 40);
    }
  }

  playWin(): void {
    const notes = [523, 587, 659, 784, 880, 1047];
    notes.forEach((f, i) => {
      setTimeout(() => this.playTone(f, 0.3, 'sine', 0.25), i * 120);
    });
  }

  playLose(): void {
    const notes = [440, 392, 349, 311];
    notes.forEach((f, i) => {
      setTimeout(() => this.playTone(f, 0.4, 'sawtooth', 0.15), i * 200);
    });
  }

  playAchievement(): void {
    this.playTone(880, 0.15, 'sine', 0.2);
    setTimeout(() => this.playTone(1047, 0.15, 'sine', 0.25), 100);
    setTimeout(() => this.playTone(1319, 0.2, 'sine', 0.3), 200);
  }

  playClick(): void {
    this.playTone(600, 0.05, 'sine', 0.15);
  }

  playCountdown(): void {
    this.playTone(440, 0.2, 'square', 0.2);
  }

  playCountdownGo(): void {
    this.playTone(880, 0.4, 'sine', 0.3);
  }

  // ── Ambient music ─────────────────────────────────────────
  private musicChordIdx = 0;
  private static CHORD_PROGRESSION = [
    [130.81, 164.81, 196.00, 246.94], // C3 major
    [110.00, 138.59, 164.81, 220.00], // Am
    [146.83, 174.61, 220.00, 293.66], // Dm
    [130.81, 164.81, 196.00, 261.63], // C3 (higher voicing)
    [116.54, 146.83, 174.61, 233.08], // Bb
    [98.00, 123.47, 146.83, 196.00],  // G (lower)
  ];

  startMusic(): void {
    if (!this.ensureCtx() || this.musicPlaying) return;
    this.musicPlaying = true;
    this.musicChordIdx = 0;
    this.playAmbientLoop();
  }

  stopMusic(): void {
    this.musicPlaying = false;
    if (this.musicOsc) {
      try { this.musicOsc.stop(); } catch { /* ignore */ }
      this.musicOsc = null;
    }
  }

  private playAmbientLoop(): void {
    if (!this.musicPlaying || !this.ctx || !this.musicGain) return;

    const chords = AudioManager.CHORD_PROGRESSION;
    const notes = chords[this.musicChordIdx % chords.length];
    this.musicChordIdx++;

    // Each chord plays for ~5s with volume envelope
    for (const freq of notes) {
      const osc = this.ctx.createOscillator();
      const gain = this.ctx.createGain();
      osc.type = 'sine';
      osc.frequency.value = freq;
      gain.gain.setValueAtTime(0.04, this.ctx.currentTime);
      gain.gain.linearRampToValueAtTime(0.12, this.ctx.currentTime + 1.5);
      gain.gain.linearRampToValueAtTime(0.08, this.ctx.currentTime + 3.5);
      gain.gain.linearRampToValueAtTime(0.001, this.ctx.currentTime + 5);
      osc.connect(gain);
      gain.connect(this.musicGain);
      osc.start();
      osc.stop(this.ctx.currentTime + 5);
    }

    // Add subtle high pad on every other chord
    if (this.musicChordIdx % 2 === 0) {
      const padFreq = notes[notes.length - 1] * 2;
      const osc = this.ctx.createOscillator();
      const gain = this.ctx.createGain();
      osc.type = 'triangle';
      osc.frequency.value = padFreq;
      gain.gain.setValueAtTime(0.01, this.ctx.currentTime);
      gain.gain.linearRampToValueAtTime(0.04, this.ctx.currentTime + 2);
      gain.gain.linearRampToValueAtTime(0.001, this.ctx.currentTime + 5);
      osc.connect(gain);
      gain.connect(this.musicGain);
      osc.start();
      osc.stop(this.ctx.currentTime + 5);
    }

    // Loop
    setTimeout(() => this.playAmbientLoop(), 4500);
  }
}

